// ─────────────────────────────────────────────────────────────────────────────
// BASE URLS — single source of truth for every host/prefix used in the app
// ─────────────────────────────────────────────────────────────────────────────
export const BASE_URLS = {
  WLB:            'https://wlbapi.toolforge.org/api/wlb',
  WIKIMEDIA_FILE: 'https://commons.wikimedia.org/wiki/Special:FilePath',
};

// ─────────────────────────────────────────────────────────────────────────────
// PATHS — just the path segments, no host, no query string
// ─────────────────────────────────────────────────────────────────────────────
export const PATHS = {
  // Mock / local routes
  CATEGORIES:        '/categories',
  TEAM:              '/team',
  STATS:             '/stats',
  SIGHTINGS:         '/sightings',

  // WLB external routes
  IMAGES_BY_SPECIES: '/images-by-species',
  IMAGES_BY_TYPE:    '/images-by-type',
  TAXONOMY_TREE:     '/taxonomy/tree-search',
  TAXONOMY_SUBTREE:  '/taxonomy/subtree',
};

// ─────────────────────────────────────────────────────────────────────────────
// ENDPOINTS — combine base URL + path + metadata in one place
// ─────────────────────────────────────────────────────────────────────────────
export const API_ENDPOINTS = {
  // ── Mock / local ──────────────────────────────────────────────────────────
  CATEGORIES: {
    path:        PATHS.CATEGORIES,
    method:      'GET',
    type:        'mock',
    description: 'Fetch all butterfly species categories',
  },
  TEAM: {
    path:        PATHS.TEAM,
    method:      'GET',
    type:        'mock',
    description: 'Fetch team members',
  },
  STATS: {
    path:        PATHS.STATS,
    method:      'GET',
    type:        'mock',
    description: 'Fetch conservation statistics',
  },
  SIGHTINGS: {
    path:        PATHS.SIGHTINGS,
    method:      'GET',
    type:        'mock',
    description: 'Fetch butterfly sightings with optional filters',
  },

  // ── WLB (Wiki Loves Butterfly) external ───────────────────────────────────
  WLB_IMAGES_BY_SPECIES: {
    path:        PATHS.IMAGES_BY_SPECIES,
    method:      'GET',
    type:        'external',
    baseUrl:     BASE_URLS.WLB,
    description: 'Fetch Wikimedia Commons images for a specific species',
  },
  WLB_IMAGES_BY_TYPE: {
    path:        PATHS.IMAGES_BY_TYPE,
    method:      'GET',
    type:        'external',
    baseUrl:     BASE_URLS.WLB,
    description: 'Fetch Wikimedia Commons images by type (e.g. feature)',
  },
  WLB_TAXONOMY_TREE: {
    path:        PATHS.TAXONOMY_TREE,
    method:      'GET',
    type:        'external',
    baseUrl:     BASE_URLS.WLB,
    description: 'Fetch taxonomy tree for a category',
  },
  WLB_TAXONOMY_SUBTREE: {
    path:        PATHS.TAXONOMY_SUBTREE,
    method:      'GET',
    type:        'external',
    baseUrl:     BASE_URLS.WLB,
    description: 'Fetch taxonomy subtree for a category',
  },
};

// ─────────────────────────────────────────────────────────────────────────────
// FULL URLS — pre-assembled strings for direct fetch() calls
// ─────────────────────────────────────────────────────────────────────────────
export const FULL_URLS = {
  /** BASE_URLS.WLB + PATHS.IMAGES_BY_TYPE + '?type=feature' */
  FEATURED_IMAGES:   `${BASE_URLS.WLB}${PATHS.IMAGES_BY_TYPE}?type=feature`,

  /** BASE_URLS.WLB + PATHS.IMAGES_BY_SPECIES  (append ?species=… at call site) */
  IMAGES_BY_SPECIES: `${BASE_URLS.WLB}${PATHS.IMAGES_BY_SPECIES}`,

  /**
   * Wikimedia Commons image URL builder.
   * Centralises every reference to BASE_URLS.WIKIMEDIA_FILE.
   *
   * @param {string} imgName  – filename or existing URL
   * @param {number} [width=400]
   * @returns {string|null}
   */
  wikiImageUrl(imgName, width = 400) {
    if (!imgName) return null;

    if (imgName.startsWith('http')) {
      if (imgName.includes('commons.wikimedia.org')) {
        // /wiki/File:Foo.jpg  →  Special:FilePath/Foo.jpg?width=N
        if (imgName.includes('/wiki/File:')) {
          const filename = imgName.split('/wiki/File:')[1].split('?')[0];
          return `${BASE_URLS.WIKIMEDIA_FILE}/${filename}?width=${width}`;
        }
        // Already a FilePath or thumbnail URL — just update/add width param
        return imgName.includes('?')
          ? imgName.replace(/width=\d+/, `width=${width}`)
          : `${imgName}?width=${width}`;
      }
      // Non-Wikimedia direct URL — return as-is
      return imgName;
    }

    // Plain filename → construct FilePath URL
    const encoded = encodeURIComponent(imgName);
    return `${BASE_URLS.WIKIMEDIA_FILE}/${encoded}?width=${width}`;
  },
};

// ─────────────────────────────────────────────────────────────────────────────
// URL Builder utility
// ─────────────────────────────────────────────────────────────────────────────
export class URLBuilder {
  constructor(baseUrl = '') {
    this.baseUrl = baseUrl;
  }

  buildUrl(path, params = {}) {
    const query = Object.entries(params)
      .filter(([, v]) => v !== undefined && v !== null && v !== '')
      .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`)
      .join('&');

    return `${this.baseUrl}${path}${query ? `?${query}` : ''}`;
  }

  buildEndpointUrl(endpoint, params = {}) {
    return new URLBuilder(endpoint.baseUrl ?? this.baseUrl)
      .buildUrl(endpoint.path, params);
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Helpers
// ─────────────────────────────────────────────────────────────────────────────

/** Find the matching endpoint definition for a given URL fragment. */
export function resolveEndpoint(url) {
  for (const [key, endpoint] of Object.entries(API_ENDPOINTS)) {
    if (typeof endpoint === 'object' && endpoint.path && url.includes(endpoint.path)) {
      return { key, endpoint, type: endpoint.type };
    }
  }
  return { key: null, endpoint: null, type: 'unknown' };
}

/** Return all endpoints of a given type ('mock' | 'external'). */
export function getEndpointsByType(type) {
  return Object.fromEntries(
    Object.entries(API_ENDPOINTS).filter(([, ep]) => ep.type === type)
  );
}

export default API_ENDPOINTS;
